# Example: running a minimal correctness eval
import anthropic

client = anthropic.Anthropic()

def eval_correctness(
    system: str,
    test_cases: list[dict],   # [{"messages": [...], "expected_topic": str}]
    model: str = "claude-opus-4-8",
    judge_model: str = "claude-haiku-4-5-20251001",
) -> float:
    passed = 0
    for tc in test_cases:
        resp = client.messages.create(
            model=model, max_tokens=512, system=system, messages=tc["messages"],
        )
        output = resp.content[0].text
        verdict = client.messages.create(
            model=judge_model, max_tokens=8,
            messages=[{"role": "user", "content":
                f"Does this response correctly address '{tc['expected_topic']}'? Yes or no.\n\n{output}"}],
        )
        if "yes" in verdict.content[0].text.lower():
            passed += 1
    return passed / len(test_cases) if test_cases else 0.0
